import{c as n,Q as t,j as a,m as s}from"./chunks/framework.Bhbi9jCp.js";const u=JSON.parse('{"title":"现代 Android 的一棵树","description":"","frontmatter":{},"headers":[],"relativePath":"androidNativeLearning/01-现代Android的一棵树.md","filePath":"androidNativeLearning/01-现代Android的一棵树.md","lastUpdated":1779789238000}'),e={name:"androidNativeLearning/01-现代Android的一棵树.md"};function d(i,o,p,l,r,c){return t(),a("div",null,[...o[0]||(o[0]=[s(`<h1 id="现代-android-的一棵树" tabindex="-1">现代 Android 的一棵树 <a class="header-anchor" href="#现代-android-的一棵树" aria-label="Permalink to &quot;现代 Android 的一棵树&quot;">​</a></h1><p>学 Android 的最大障碍不是&quot;API 太多&quot;,是<strong>心智模型没建起来</strong>。一个写过几年 Java + XML 的人,如果还把 Android 当&quot;多个 Activity 通过 Intent 互相调&quot;,那一打开 Compose 项目就会立刻懵——单 Activity?Composable?重组?状态怎么传?这一篇不教任何 API,只讲一件事:<strong>现代 Android 到底长什么样</strong>。</p><blockquote><p>一句话先记住:<strong>现代 Android 是一棵被状态驱动重组的 UI 树,挂在单个 Activity 上,被一组 ViewModel 持有状态,被协程驱动副作用。其余 Jetpack 库,都是这棵树的扩展或副作用边界。</strong> 这句话听上去很抽象,但后面 21 篇都是它的推论。</p></blockquote><hr><h2 id="一、忘掉-java-xml-那一代-android" tabindex="-1">一、忘掉 Java + XML 那一代 Android <a class="header-anchor" href="#一、忘掉-java-xml-那一代-android" aria-label="Permalink to &quot;一、忘掉 Java + XML 那一代 Android&quot;">​</a></h2><p>很多人对 Android 的初始印象是&quot;Java 写业务、XML 写界面、<code>Activity</code> 与 <code>Fragment</code> 组合生命周期、<code>AsyncTask</code> 跑后台&quot;。这套心智在 2017 年之前是对的,在 2026 年是<strong>陈旧的</strong>。</p><table tabindex="0"><thead><tr><th>维度</th><th>旧 Android(2010-2017)</th><th>现代 Android(2021-)</th></tr></thead><tbody><tr><td>语言</td><td>Java</td><td><strong>Kotlin 2.0</strong></td></tr><tr><td>UI</td><td>XML View + <code>findViewById</code></td><td><strong>Jetpack Compose</strong>(声明式)</td></tr><tr><td>屏幕</td><td>每屏一个 <code>Activity</code>,<code>Intent</code> 跳转</td><td><strong>单 Activity</strong> + Compose Navigation</td></tr><tr><td>异步</td><td><code>AsyncTask</code> / <code>Handler</code> / RxJava</td><td><strong>协程 + Flow</strong></td></tr><tr><td>状态</td><td>View 双向绑定</td><td><strong>State → UI 单向流</strong></td></tr><tr><td>DI</td><td>手写 / Dagger 2</td><td><strong>Hilt</strong>(KSP)</td></tr><tr><td>后台</td><td><code>Service</code> + <code>JobScheduler</code></td><td><strong>WorkManager</strong>(单一入口)</td></tr><tr><td>构建</td><td>Gradle Groovy + KAPT</td><td><strong>Gradle KTS + Version Catalog + KSP</strong></td></tr><tr><td>发布</td><td>APK 直传</td><td><strong>App Bundle</strong>(AAB)+ Play Console</td></tr></tbody></table><p><strong>最要命的差别不在 API 数量,而在心智方向</strong>:旧 Android 是&quot;命令式 + 多入口&quot;,你拿到 <code>Activity</code> 引用、<code>findViewById</code> 拿到 View、然后命令式地 <code>textView.setText(&quot;hello&quot;)</code>。现代 Android 是&quot;声明式 + 状态驱动&quot;,你声明的是&quot;当状态长这样时 UI 应该长这样&quot;,剩下的让 Compose runtime 自己重组。</p><blockquote><p>如果你脑子里 Android 的心智还停留在&quot;多个 Activity 互相跳&quot;,那看 Navigation Compose 时会一直问&quot;这怎么 startActivity&quot;,看 ViewModel 时会一直问&quot;它什么时候 onDestroy&quot;——问题不在 API,在你以为 Android 还是 2015 年那一套。</p></blockquote><hr><h2 id="二、那棵树长什么样" tabindex="-1">二、那棵树长什么样 <a class="header-anchor" href="#二、那棵树长什么样" aria-label="Permalink to &quot;二、那棵树长什么样&quot;">​</a></h2><p>现代 Android 应用,<strong>整个进程只有一个 Activity</strong>。这个 Activity 调 <code>setContent { App() }</code>,从此整个 UI 是一棵 Composable 函数构成的树。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>进程(Application)</span></span>
<span class="line"><span>└── ComponentActivity(唯一一个)</span></span>
<span class="line"><span>    └── setContent { ... }</span></span>
<span class="line"><span>        └── App()                  ← Composable 根节点</span></span>
<span class="line"><span>            ├── NavHost(...)       ← 路由,管&quot;现在显示哪一屏&quot;</span></span>
<span class="line"><span>            │   ├── HomeScreen()</span></span>
<span class="line"><span>            │   │   ├── TopBar()</span></span>
<span class="line"><span>            │   │   └── NoteList(notes: List&lt;Note&gt;)</span></span>
<span class="line"><span>            │   │       └── NoteRow(...) × N</span></span>
<span class="line"><span>            │   └── DetailScreen(...)</span></span>
<span class="line"><span>            └── BottomBar(...)</span></span></code></pre></div><p>每个节点(<code>HomeScreen</code>、<code>NoteList</code>、<code>NoteRow</code>)都是一个普通的 Kotlin 函数,标注 <code>@Composable</code>。这些函数<strong>只读状态、生成 UI 描述</strong>,自己不持有任何字段、不订阅生命周期、不操作 View。</p><p><strong>这棵树的关键性质</strong>:</p><ol><li><strong>声明式</strong>——你写&quot;在某状态下 UI 长什么样&quot;,不写&quot;如何把 UI 从 A 状态改成 B 状态&quot;。</li><li><strong>可重新调用</strong>——同一个 Composable 函数会被反复调用,每次叫一次&quot;重组&quot;(recomposition)。</li><li><strong>只读状态</strong>——Composable 读 <code>State&lt;T&gt;</code>,状态变了 Compose 自动重组依赖它的节点。</li><li><strong>没有 View 引用</strong>——你拿不到也不需要拿 <code>TextView</code> 这种对象,只描述输出。</li></ol><p>后面 5-9 篇全在讲这棵树:怎么搭、怎么重组、怎么布局、怎么动画。</p><hr><h2 id="三、谁持有状态-viewmodel" tabindex="-1">三、谁持有状态:ViewModel <a class="header-anchor" href="#三、谁持有状态-viewmodel" aria-label="Permalink to &quot;三、谁持有状态:ViewModel&quot;">​</a></h2><p>Composable 函数是&quot;纯函数&quot;,每次重组都会重跑——所以它<strong>不能自己存状态</strong>。状态必须存在比 Composable 寿命更长的地方,这个地方叫 <code>ViewModel</code>。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ComponentActivity ─── ViewModelStoreOwner ─── 一组 ViewModel</span></span>
<span class="line"><span>                                              ├── HomeViewModel</span></span>
<span class="line"><span>                                              ├── NoteDetailViewModel</span></span>
<span class="line"><span>                                              └── ...</span></span>
<span class="line"><span>                                                   ↓ uiState: StateFlow&lt;UiState&gt;</span></span>
<span class="line"><span>                                                   ↓ (collect)</span></span>
<span class="line"><span>                                              Composable 读 → 重组</span></span>
<span class="line"><span>                                                   ↑</span></span>
<span class="line"><span>                                                   ↑ 事件向上</span></span>
<span class="line"><span>                                              用户操作(点击 / 输入)</span></span></code></pre></div><p><code>ViewModel</code> 是一个**&quot;比 UI 寿命长、被进程级别管理&quot;的对象**:屏幕旋转、配置变更、用户回到这一屏,<code>ViewModel</code> 都不重建。Composable 通过 <code>viewModel()</code> 拿到它,读它暴露的 <code>StateFlow&lt;UiState&gt;</code>,把 UI 事件传回它的方法。</p><blockquote><p>这就是 <strong>UDF(Unidirectional Data Flow,单向数据流)</strong>:<strong>状态从 ViewModel 流到 UI,事件从 UI 流回 ViewModel,中间没有反向数据绑定</strong>。10 篇会专门讲。</p></blockquote><hr><h2 id="四、副作用从哪里出去-协程" tabindex="-1">四、副作用从哪里出去:协程 <a class="header-anchor" href="#四、副作用从哪里出去-协程" aria-label="Permalink to &quot;四、副作用从哪里出去:协程&quot;">​</a></h2><p>UI 树是纯的,ViewModel 也只是个状态容器,真正&quot;做事&quot;的是<strong>协程</strong>——读数据库、发网络、写文件、调系统服务。所有这些操作在 ViewModel 里启动,绑定到 <code>viewModelScope</code>,ViewModel 被销毁时<strong>自动取消所有未完成的协程</strong>。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ViewModel.viewModelScope</span></span>
<span class="line"><span>   ├── launch { repository.fetchNotes() }        ← 网络请求</span></span>
<span class="line"><span>   ├── launch { dao.observeAll().collect { ... } } ← 数据库观察</span></span>
<span class="line"><span>   └── launch { workManager.enqueue(...) }       ← 后台任务</span></span></code></pre></div><p>这就是<strong>结构化并发</strong>:协程的生命周期挂在某个 scope 上,scope 死了协程自动死,没有&quot;孤儿协程&quot;在后台烧 CPU。04 篇展开。</p><hr><h2 id="五、jetpack-是几十个独立库-不是一个-sdk" tabindex="-1">五、Jetpack 是几十个独立库,不是一个 SDK <a class="header-anchor" href="#五、jetpack-是几十个独立库-不是一个-sdk" aria-label="Permalink to &quot;五、Jetpack 是几十个独立库,不是一个 SDK&quot;">​</a></h2><p>很多人以为 &quot;Jetpack&quot; 是个安装包,装上就有所有功能。<strong>不是</strong>。Jetpack 是 Google 在 <code>androidx.*</code> 命名空间下维护的<strong>一组独立库</strong>,每个库各自版本号:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>androidx.compose.ui:1.7.4         ← UI</span></span>
<span class="line"><span>androidx.lifecycle:2.8.7          ← ViewModel</span></span>
<span class="line"><span>androidx.navigation.compose:2.8.4 ← 路由</span></span>
<span class="line"><span>androidx.room:2.6.1               ← 数据库</span></span>
<span class="line"><span>androidx.work.runtime-ktx:2.10.0  ← 后台任务</span></span>
<span class="line"><span>androidx.activity.compose:1.9.3   ← Activity-Compose 桥</span></span>
<span class="line"><span>com.google.dagger:hilt-android:2.52 ← DI(不在 androidx 但属于 Jetpack 推荐)</span></span></code></pre></div><p><strong>这些库没有强绑定</strong>,你按需引入。一个最小 Compose App 只需要 5-6 个库就能跑;一个完整产品大概 15-20 个。每多一个库,APK 体积、编译时间、潜在版本冲突都增加——所以<strong>Jetpack 全家桶不等于&quot;必须每个都用&quot;</strong>。</p><blockquote><p>Compose 子家族通过 <code>androidx.compose:compose-bom</code> 这个 BOM(Bill of Materials)统一管理版本,只指定 BOM 版本,内部库的版本自动对齐。02 篇展开。</p></blockquote><hr><h2 id="六、android-sdk-jetpack-kotlin-android-studio-四件事的关系" tabindex="-1">六、Android SDK / Jetpack / Kotlin / Android Studio:四件事的关系 <a class="header-anchor" href="#六、android-sdk-jetpack-kotlin-android-studio-四件事的关系" aria-label="Permalink to &quot;六、Android SDK / Jetpack / Kotlin / Android Studio:四件事的关系&quot;">​</a></h2><p>新读者最容易混淆这四个名词,实际上它们各自层级不同:</p><ul><li><strong>Android SDK</strong>——Google 按 API Level 发布的平台 API,装在 <code>~/Library/Android/sdk/platforms/android-35/</code>。Android 15 = API 35。</li><li><strong>Jetpack</strong>——上面说过,几十个 <code>androidx.*</code> 库。<strong>与 Android SDK 版本正交</strong>——即便你 minSdk 26,也能用 Jetpack 最新版的 ViewModel / Navigation / Room,因为 Jetpack 库自己内部兼容老 API Level。</li><li><strong>Kotlin</strong>——JetBrains 维护的 JVM 语言,2024-05 发布 2.0 默认启用 K2 编译器。与 SDK / Jetpack 都正交。</li><li><strong>Android Studio</strong>——基于 IntelliJ 的 IDE,版本叫 Hedgehog / Iguana / Koala 等。它<strong>只是 IDE</strong>,完全可以用纯命令行 <code>./gradlew assembleDebug</code> 跑构建。</li></ul><p>四件事的关系:<strong>Android Studio 调 AGP 调 Gradle 调 Kotlin 编译器,产出兼容某个 API Level 的 APK / AAB,里面打包了用到的 Jetpack 库与业务代码</strong>。</p><hr><h2 id="七、targetsdk-与-minsdk-不是版本号-是契约" tabindex="-1">七、targetSdk 与 minSdk:不是版本号,是契约 <a class="header-anchor" href="#七、targetsdk-与-minsdk-不是版本号-是契约" aria-label="Permalink to &quot;七、targetSdk 与 minSdk:不是版本号,是契约&quot;">​</a></h2><p><code>minSdk</code> / <code>targetSdk</code> 是两个经常被误解的数字:</p><ul><li><strong>minSdk = 26</strong>——意思是&quot;这个 App 不允许装在 Android 8.0 以下的设备上&quot;。选 26 覆盖 95%+ 装机,且能用 <code>NotificationChannel</code>、Adaptive Icons 这些现代能力。</li><li><strong>targetSdk = 35</strong>——意思是&quot;我声明:我的代码已经按 Android 15 的行为写过、测过&quot;。Play Console 强制要求 targetSdk ≥ 34(2024-08 起)、≥ 35(2025-08 起)。</li></ul><p><code>targetSdk</code> 不是 UI 开关,是<strong>契约</strong>。不升 targetSdk 时,系统会给一堆兼容垫片(edge-to-edge 不强制、后台限制放宽);升上去后这些垫片消失,你必须主动处理新行为(<code>WindowInsets</code>、Foreground Service Type、Predictive Back Gesture)。</p><p>NotedX 这个系列样例应用钉死 <strong>minSdk = 26 / targetSdk = 35</strong>。</p><hr><h2 id="八、本系列的整体地图" tabindex="-1">八、本系列的整体地图 <a class="header-anchor" href="#八、本系列的整体地图" aria-label="Permalink to &quot;八、本系列的整体地图&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>01     心智总览(这篇)</span></span>
<span class="line"><span>02-04  地基:构建 → Kotlin → 协程与 Flow</span></span>
<span class="line"><span>       这一段是&quot;会写 Android&quot; 的前提,顺序不能跳</span></span>
<span class="line"><span></span></span>
<span class="line"><span>05-09  UI 一族:Compose 入口 / 重组 / 输入 / 布局 / 动画</span></span>
<span class="line"><span>       这一段是&quot;会写界面&quot; 的核心,占整本最大篇幅</span></span>
<span class="line"><span></span></span>
<span class="line"><span>10-14  架构与闭环:ViewModel / Navigation / Hilt / Room / Retrofit</span></span>
<span class="line"><span>       这一段读完,你能从零搭一个能联网能存数据的 App</span></span>
<span class="line"><span></span></span>
<span class="line"><span>15-19  系统能力:权限 / 后台 / 推送 / 相机 / 系统集成</span></span>
<span class="line"><span>       按需看,做什么功能看什么</span></span>
<span class="line"><span></span></span>
<span class="line"><span>20-22  工程化与发布:多模块 / 性能 / 测试与上架</span></span>
<span class="line"><span>       上架前必看</span></span></code></pre></div><p><strong>优先级</strong>:01-14 每篇都建议看;15-19 按需;20-22 真上架前再回头读。</p><hr><h2 id="九、踩坑提醒-总览版-后面每篇细讲" tabindex="-1">九、踩坑提醒(总览版,后面每篇细讲) <a class="header-anchor" href="#九、踩坑提醒-总览版-后面每篇细讲" aria-label="Permalink to &quot;九、踩坑提醒(总览版,后面每篇细讲)&quot;">​</a></h2><ol><li><strong>把 Compose 当 React 用</strong>——Compose 不是 React 的 Kotlin 版,重组成本完全不一样,06 / 21 篇讲清楚。</li><li><strong>多 Activity + Fragment 心智迁移过来</strong>——Fragment 在现代 Android 几乎没有位置,99% 场景都用 Composable + Navigation 代替,11 篇展开。</li><li><strong>ViewModel 当单例用</strong>——<code>ViewModel</code> 是和 UI 绑定的,有 scope,过期就回收,18 / 11 / 10 篇会反复提。</li><li><strong>协程在 Activity / Composable 里裸 launch</strong>——不绑 scope 的协程是孤儿,泄漏隐患极大,04 篇讲。</li><li><strong>不升 targetSdk</strong>——Play Console 一旦卡截止日期,你只剩几周时间还一整年的债,通常会引出发布事故。</li><li><strong>以为 RxJava 还有用</strong>——本系列没有一行 RxJava,Flow 完全替代它在 Android 的位置,04 篇展开。</li><li><strong>Compose 与 XML View 混用</strong>——<code>AndroidView</code> / <code>ComposeView</code> 互嵌技术上可以,但新项目 99% 不该做,代价是双状态管理 + 双主题 + 双测试栈。</li><li><strong>认为单 Activity 难写</strong>——单 Activity 不是&quot;更难&quot;,是&quot;更简单&quot;:没有 Activity 之间的数据传递,没有 <code>onActivityResult</code>,生命周期心智从 5 段缩到 1 段。</li><li><strong>过早多模块</strong>——单模块能写到第 15 篇,提前拆模块只是给自己制造痛苦,20 篇展开。</li><li><strong>沉迷&quot;全家桶&quot;</strong>——Jetpack 几十个库,你的 App 大概率只需要其中 15 个,不要把&quot;用得多&quot;当成&quot;工程好&quot;。</li></ol><hr><p>下一篇 <code>02-项目骨架与 Gradle 构建工具链.md</code>,把 <code>build.gradle.kts</code>、<code>libs.versions.toml</code>、AGP × Kotlin × Compose Compiler 版本对齐、KSP 全套钉死,给出可直接复制的 NotedX 完整构建脚本。</p>`,54)])])}const h=n(e,[["render",d]]);export{u as __pageData,h as default};
